__CPROVER_ensures(*outsize ==
                  __CPROVER_old(*outsize) + (__CPROVER_old(*bp) == 0 ? 1 : 0))
/* The bit cursor advances by one, modulo 8. */
__CPROVER_ensures(*bp == ((__CPROVER_old(*bp) + 1) & 7))
{
